<template>
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>{{ Gaceta.gaceta_titulo }}</h1>
          </div>


                <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
                <h5>
                  <a style="cursor: pointer" @click="clickBack()">GACETA</a>
                </h5>
                <h3>{{ Gaceta.gaceta_titulo }}</h3>

        </div>
      </div>
    </div>
  </div>

  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <!-- Start Left Column -->
      <div class="col-sm-8 blog-left">

        <div class="col-lg-8 col-12" v-if="errorGet">
          <h1>Documento inexistente</h1>
        </div>
        <ul class="blog-listing detail">
          <li>
            <!-- <img src="images/blog-detail-img.jpg" 
                      class="img-responsive" alt=""> -->

            <!-- <a :href="url_api + '/Gaceta/' + Gaceta.gaceta_documento" target="_blank">
                  <vue-pdf-embed
                    :source="url_api + '/Gaceta/' + Gaceta.gaceta_documento"
                    :disableTextLayer="true"
                  />
                </a> -->
            <div class="pdf-container">
              <a :href="url_api + '/Gaceta/' + Gaceta.gaceta_documento" target="_blank">
                <div class="pdf-wrapper">
                  <vue-pdf-embed :source="url_api + '/Gaceta/' + Gaceta.gaceta_documento" :disableTextLayer="true"
                    class="pdf-embed" />
                </div>
              </a>
            </div>

            <h2>{{ Gaceta.gaceta_titulo }}</h2>
            <ul class="post-detail">
              <li><span class="icon-calander-icon ico"></span><span class="bold">{{ dmy(Gaceta.gaceta_fecha) }}</span>
              </li>
              <!-- <li><span class="icon-chat-icon ico"></span><span class="bold">14</span> Comments</li> -->
            </ul>

          </li>
        </ul>


      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">

        <SidebarCustom></SidebarCustom>

      </div>
      <!-- End Right Column -->

    </div>
  </div>
</template>

<style scoped>
.pdf-container {
  max-height: 600px;
  overflow: auto;
  border: 3px solid #000000;
}

.pdf-wrapper {
  width: 100%;
  height: 100%;
}

.pdf-embed {
  width: 100%;
  height: 100%;
}

.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>
import { mapState } from "vuex";
// import HeaderCustom from "@/components/HeaderCustom.vue";
import SidebarCustom from "@/components/SidebarCustom.vue";
import VuePdfEmbed from "vue-pdf-embed";
export default {
  name: "detalleGaceta",
  data() {
    return {
      Gaceta: {},
      errorGet: false,
    };
  },
  components: { SidebarCustom, VuePdfEmbed },
  computed: {
    ...mapState(["url_api"]),
  },
  methods: {
    dmy(fecha) {
      if (fecha != undefined) {
        const meses = [
          "enero",
          "febrero",
          "marzo",
          "abril",
          "mayo",
          "junio",
          "julio",
          "agosto",
          "septiembre",
          "octubre",
          "noviembre",
          "diciembre",
        ];
        let fechaCadena = fecha.substr(0, 10);
        let fechaArray = fechaCadena.split("-");
        return (
          fechaArray[2] +
          " de " +
          meses[fechaArray[1] - 1] +
          " de " +
          fechaArray[0]
        );
      }
    },
    async getGaceta() {
      try {
        let res = await this.axios.get(
          "/api/gacetauniv/" + this.$route.params.idGac
        );
        this.Gaceta = res.data.Descripcion;
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
        if (error.response.status == 500) {
          this.errorGet = true;
          this.$store.commit("loading");
        }
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    setPdf() {
      // :src="url_api + '/Gaceta/' + Gaceta.gaceta_documento"
      let pdf = document.getElementById("frame-pdf");
      pdf.setAttribute(
        "src",
        this.url_api + "/Gaceta/" + this.Gaceta.gaceta_documento
      );
    },
  },
  mounted() {
    this.getGaceta();
  },
  created() {
    this.getGaceta();
  },
};
</script>